fun solve(nums: Array<Long>): Long {
    var count = 0L
    val n = nums.size
    for (i in 0 until n) {
        for (j in i + 1 until n) {
            val a = nums[i]
            val b = nums[j]
            val aAbs = a.abs()
            val bAbs = b.abs()
            val minAbs = minOf(aAbs, bAbs)
            val maxAbs = maxOf(aAbs, bAbs)

            val diff = (a - b).abs()
            val sum = (a + b).abs()

            val minVal = minOf(diff, sum)
            val maxVal = maxOf(diff, sum)

            if (minVal <= minAbs && maxVal >= maxAbs) {
                count++
            }
        }
    }
    return count
}
